module top_module(
    input CLK,
    input LOAD,
    input [3:0] DATA,
    output reg [3:0] Q
);reg [3:0] unused_reg_out;

always @(posedge CLK) begin
    if (LOAD) begin
        unused_reg_out <= DATA;
    end else begin
        unused_reg_out <= {unused_reg_out[2:0], 1'b0};
    end
end

assign Q = unused_reg_out;

endmodule
